SELECT 
    (SELECT COUNT(user_discount_id) FROM user_discounts) AS total_discounts_used,
    (SELECT SUM(points) FROM reward_points) AS total_rewards_earned;

SELECT user_id 
FROM trips 
WHERE trip_id = 1 AND bike_id = 0;

SELECT COUNT(*) AS total_trips
FROM trips
WHERE user_zip_code = '10021';

SELECT SUM(total_distance) AS total_distance
FROM users
WHERE zip_code = '94518';
